  ('heelevel3-e9ff7ca9-moex-00170', 'heelevel3-e9ff7ca9', 'heelevel3-e9ff7ca9-moex-112-3082b5f1', 'sub-heelevel3-e9ff7ca9-04', NULL, 'single_choice', '依地方制度法規定，中央主管機關針對直轄市政府所辦理自治事項之監督，下列敘述何者錯誤？', '["地方政府辦理自治事項得自為立法並執行而負其政策規劃及行政執行責任", "地方政府辦理自治事項有違憲法或法律規定時，仍得予以撤銷、變更、廢止或停止其執行", "直轄市政府辦理自治事項違法時，由中央主管機關報行政院予以撤銷、變更、廢止或停止其執行", "地方政府辦理自治事項若有違背憲法或法律之疑義時，於司法院解釋前，中央主管機關得先予 以撤銷之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:46+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "303", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "客家事務行政"}'::jsonb, NULL),
